import{c as t,Q as n,j as s,m as o}from"./chunks/framework.rlpw0eGz.js";const d=JSON.parse('{"title":"Misskey Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/misskey.md","filePath":"channels/misskey.md","lastUpdated":1776332711000}'),a={name:"channels/misskey.md"};function i(r,e,l,c,h,u){return n(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="misskey-channel-configuration" tabindex="-1">Misskey Channel Configuration <a class="header-anchor" href="#misskey-channel-configuration" aria-label="Permalink to &quot;Misskey Channel Configuration&quot;">​</a></h1><p>Memoh can connect a bot to a Misskey server so it can read inbound mentions and reply as a Misskey account. This adapter is best for text-first social interactions on self-hosted or public Misskey instances.</p><h2 id="step-1-prepare-a-misskey-account-and-token" tabindex="-1">Step 1: Prepare A Misskey Account And Token <a class="header-anchor" href="#step-1-prepare-a-misskey-account-and-token" aria-label="Permalink to &quot;Step 1: Prepare A Misskey Account And Token&quot;">​</a></h2><ol><li>Sign in to the Misskey instance you want to use.</li><li>Create or choose the account that should represent your bot.</li><li>Generate an <strong>Access Token</strong> for that account.</li></ol><p>Memoh needs:</p><ul><li><strong>Instance URL</strong>: for example <code>https://misskey.io</code></li><li><strong>Access Token</strong>: a token for the bot account</li></ul><p>The exact token-creation UI varies by Misskey instance. Make sure the token is allowed to read inbound events for the bot account and publish replies.</p><h2 id="step-2-configure-memoh" tabindex="-1">Step 2: Configure Memoh <a class="header-anchor" href="#step-2-configure-memoh" aria-label="Permalink to &quot;Step 2: Configure Memoh&quot;">​</a></h2><ol><li>Open your bot in the Memoh Web UI.</li><li>Go to <strong>Platforms</strong>.</li><li>Click <strong>Add Channel</strong> and choose <strong>Misskey</strong>.</li><li>Enter the <strong>Instance URL</strong>.</li><li>Paste the <strong>Access Token</strong>.</li><li>Click <strong>Save and Enable</strong>.</li></ol><p>Memoh uses these credentials to discover the bot identity and start the Misskey connection.</p><h2 id="step-3-start-chatting" tabindex="-1">Step 3: Start Chatting <a class="header-anchor" href="#step-3-start-chatting" aria-label="Permalink to &quot;Step 3: Start Chatting&quot;">​</a></h2><p>After the channel is enabled, users can interact with the bot on that Misskey instance.</p><p>Misskey in Memoh is generally best suited for:</p><ul><li>replies to users</li><li>text and Markdown-style output</li><li>reaction-aware social conversations</li></ul><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Text</strong></li><li><strong>Markdown</strong></li><li><strong>Replies</strong></li><li><strong>Reactions</strong></li></ul><p>Current limitations:</p><ul><li><strong>No attachments / media upload</strong></li><li><strong>No streaming output</strong></li></ul>',18)])])}const g=t(a,[["render",i]]);export{d as __pageData,g as default};
